from flask import Flask, render_request, redirect, url_for, request, render_template
from database import db
from models import URL
import string
import random

app = Flask(__name__)
app.config['SQLALCHEMY_DATABASE_URI'] = 'sqlite:///urls.db'
app.config['SQLALCHEMY_TRACK_MODIFICATIONS'] = False

db.init_app(app)

def generate_short_id(length=6):
    chars = string.ascii_letters + string.digits
    return ''.join(random.choice(chars) for _ in range(length))

@app.before_first_request
def create_tables():
    db.create_all()

@app.route('/', methods=['GET', 'POST'])
def index():
    if request.method == 'POST':
        original_url = request.form['url']
        short_id = generate_short_id()

        new_url = URL(original_url=original_url, short_id=short_id)
        db.session.add(new_url)
        db.session.commit()

        return render_template('index.html', short_url=request.host_url + short_id)

    return render_template('index.html')

@app.route('/<short_id>')
def redirection(short_id):
    url_entry = URL.query.filter_by(short_id=short_id).first_or_404()
    return redirect(url_entry.original_url)

if __name__ == '__main__':
    app.run(debug=True)
import string
import random
from database import get_db_connection

def generate_short_url(length=6):
    chars = string.ascii_letters + string.digits
    return ''.join(random.choice(chars) for _ in range(length))

class URLModel:
    @staticmethod
    def create_url(original_url):
        conn = get_db_connection()
        short_url = generate_short_url()

        # Ensure uniqueness
        while conn.execute('SELECT id FROM urls WHERE short_url = ?', (short_url,)).fetchone():
            short_url = generate_short_url()

        conn.execute('INSERT INTO urls (original_url, short_url) VALUES (?, ?)',
                     (original_url, short_url))
        conn.commit()
        conn.close()
        return short_url

    @staticmethod
    def get_original_url(short_url):
        conn = get_db_connection()
        url = conn.execute('SELECT original_url FROM urls WHERE short_url = ?',
                           (short_url,)).fetchone()
        conn.close()
        if url:
            return url['original_url']
        return None

    @staticmethod
    def get_all_urls():
        conn = get_db_connection()
        urls = conn.execute('SELECT * FROM urls').fetchall()
        conn.close()
        return urls
import sqlite3

def get_db_connection():
    conn = sqlite3.connect('database.db')
    conn.row_factory = sqlite3.Row
    return conn

def init_db():
    conn = get_db_connection()
    conn.execute('CREATE TABLE IF NOT EXISTS urls (id INTEGER PRIMARY KEY AUTOINCREMENT, original_url TEXT NOT NULL, short_url TEXT NOT NULL UNIQUE)')
    conn.commit()
    conn.close()

if __name__ == '__main__':
    init_db()
